// N8N - Gerador de Catálogo Markdown para Restaurante

const CONFIG = {
  tituloH1: '🍽️ Cardápio Completo',
  nomeRestaurante: 'Pizzaria Dona Rosa',
  template: 'padrao', // 'padrao', 'compacto', 'premium', 'minimalista'
  incluirImagens: true,
  incluirIndice: true,
  incluirEstatisticas: true,
  agruparPorCategoria: true,

  // OPÇÕES DE LAYOUT
  layoutImagem: 'destaque', // 'destaque', 'lateral', 'compacta', 'sem-imagem'
  mostrarPrecoDestaque: true,
  mostrarInativos: false, // Mostrar produtos com active: false

  // EMOJIS POR CATEGORIA (personalizável)
  emojisPorCategoria: {
    'Pizza Tradicional': '🍕',
    'Pizza Especial': '🍕⭐',
    'Pizza Doce': '🍕🍫',
    'Pastel': '🥟',
    'Porções e Aperitivos': '🍟',
    'Bebidas': '🥤',
    'default': '🍴'
  }
};

// ============================================
// FUNÇÕES UTILITÁRIAS
// ============================================

// Formata preço para BRL
function formatarPreco(preco) {
  if (!preco) return 'Preço sob consulta';
  const num = parseFloat(preco);
  if (isNaN(num)) return 'Preço sob consulta';
  return num.toLocaleString('pt-BR', { 
    style: 'currency', 
    currency: 'BRL', 
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });
}

// Limpa texto removendo HTML e excesso de quebras
function limparTexto(texto) {
  if (!texto) return '';
  return String(texto)
    .replace(/<[^>]*>/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

// Primeira letra maiúscula
function capitalizar(str) {
  if (!str) return '';
  return str.charAt(0).toUpperCase() + str.slice(1).toLowerCase();
}

// Cria slug para anchors
function slugify(texto) {
  if (!texto) return '';
  return texto.toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^\w\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '');
}

// Extrai informações da descrição (calorias, alergênicos, etc)
function extrairInfoDescricao(descricao) {
  if (!descricao) return { principal: '', calorias: null, extras: [] };

  const texto = limparTexto(descricao);
  const partes = texto.split(',').map(p => p.trim());

  let principal = '';
  let calorias = null;
  const extras = [];

  partes.forEach(parte => {
    if (parte.match(/\d+\s*(cal|kcal|calorias)/i)) {
      calorias = parte;
    } else if (principal === '') {
      principal = parte;
    } else {
      extras.push(parte);
    }
  });

  return { principal, calorias, extras };
}

// Obtém emoji para categoria
function getEmojiCategoria(categoria) {
  if (!categoria) return CONFIG.emojisPorCategoria.default;

  // Busca exata
  if (CONFIG.emojisPorCategoria[categoria]) {
    return CONFIG.emojisPorCategoria[categoria];
  }

  // Busca parcial (case-insensitive)
  const categoriaLower = categoria.toLowerCase();
  for (const [key, emoji] of Object.entries(CONFIG.emojisPorCategoria)) {
    if (key.toLowerCase().includes(categoriaLower) || 
        categoriaLower.includes(key.toLowerCase())) {
      return emoji;
    }
  }

  return CONFIG.emojisPorCategoria.default;
}

// ============================================
// VALIDAÇÃO DE PRODUTOS
// ============================================

function validarProduto(produto, index) {
  const erros = [];

  if (!produto.name || produto.name.trim() === '') {
    erros.push(`Produto #${index + 1}: campo 'name' obrigatório`);
  }

  if (!produto.price && produto.price !== 0) {
    erros.push(`Produto #${index + 1}: campo 'price' obrigatório`);
  }

  if (produto.price && isNaN(parseFloat(produto.price))) {
    erros.push(`Produto #${index + 1}: 'price' deve ser um número`);
  }

  return erros;
}

function validarTodosProdutos(produtos) {
  const todosErros = [];

  produtos.forEach((produto, index) => {
    const erros = validarProduto(produto, index);
    todosErros.push(...erros);
  });

  return todosErros;
}

// ============================================
// GERAÇÃO DE IMAGENS
// ============================================

function gerarImagemProduto(produto, layout = CONFIG.layoutImagem) {
  if (!CONFIG.incluirImagens || !produto.image_url) {
    return '';
  }

  const alt = limparTexto(produto.name) || 'Produto';
  const imgMarkdown = `![${alt}](${produto.image_url})`;

  switch (layout) {
    case 'destaque':
      // Imagem em destaque (bloco próprio)
      return `${imgMarkdown}\n\n`;

    case 'lateral':
      // Imagem + info na mesma linha (tabela)
      return 'lateral'; // Será tratado no template

    case 'compacta':
      // Imagem pequena inline
      return `${imgMarkdown} `;

    case 'sem-imagem':
    default:
      return '';
  }
}

// ============================================
// TEMPLATES DE PRODUTO
// ============================================

function templatePadrao(produto, index, categoriaSlug) {
  const slug = slugify(produto.name || 'produto');
  const info = extrairInfoDescricao(produto.description);
  const img = gerarImagemProduto(produto, CONFIG.layoutImagem);

  let md = '';

  // Título do produto
  md += `### ${limparTexto(produto.name)} {#produto-${produto.id || index}-${slug}}\n\n`;

  // Imagem (se layout não for lateral)
  if (img && img !== 'lateral') {
    md += img;
  }

  // Layout lateral (tabela)
  if (img === 'lateral' && produto.image_url) {
    md += `| | |\n`;
    md += `|---|---|\n`;
    md += `| ![${limparTexto(produto.name)}](${produto.image_url}) | `;
    md += `**${formatarPreco(produto.price)}**<br><br>`;
    if (info.principal) md += `${info.principal}<br>`;
    if (info.calorias) md += `*${info.calorias}*<br>`;
    if (info.extras.length > 0) md += `${info.extras.join(' • ')}`;
    md += ` |\n\n`;

    if (!CONFIG.mostrarInativos && produto.active === false) {
      md += `> ⚠️ *Produto temporariamente indisponível*\n\n`;
    }

    return md;
  }

  // Preço em destaque
  if (CONFIG.mostrarPrecoDestaque) {
    md += `**💰 ${formatarPreco(produto.price)}**\n\n`;
  }

  // Descrição principal
  if (info.principal) {
    md += `${info.principal}\n\n`;
  }

  // Informações extras
  const extras = [];
  if (info.calorias) extras.push(info.calorias);
  if (info.extras.length > 0) extras.push(...info.extras);

  if (extras.length > 0) {
    md += `*${extras.join(' • ')}*\n\n`;
  }

  // Status de disponibilidade
  if (!CONFIG.mostrarInativos && produto.active === false) {
    md += `> ⚠️ *Produto temporariamente indisponível*\n\n`;
  }

  // ID para referência
  if (produto.id) {
    md += `*Ref: #${produto.id}*\n\n`;
  }

  return md;
}

function templateCompacto(produto, index, categoriaSlug) {
  const slug = slugify(produto.name || 'produto');
  const info = extrairInfoDescricao(produto.description);

  let md = '';

  // Linha única com todas as informações
  md += `**${limparTexto(produto.name)}** • ${formatarPreco(produto.price)}`;

  if (info.calorias) {
    md += ` • ${info.calorias}`;
  }

  if (produto.image_url && CONFIG.incluirImagens) {
    md += ` • [Ver foto](${produto.image_url})`;
  }

  if (!CONFIG.mostrarInativos && produto.active === false) {
    md += ` ⚠️`;
  }

  md += `\n\n`;

  return md;
}

function templatePremium(produto, index, categoriaSlug) {
  const slug = slugify(produto.name || 'produto');
  const info = extrairInfoDescricao(produto.description);
  const img = gerarImagemProduto(produto, 'destaque');

  let md = '';

  md += `---\n\n`;

  // Título destacado
  md += `## ${limparTexto(produto.name)} {#produto-${produto.id || index}-${slug}}\n\n`;

  // Imagem em destaque
  if (img) {
    md += img;
  }

  // Blockquote com informações principais
  md += `> ### 💰 ${formatarPreco(produto.price)}\n`;

  if (info.principal) {
    md += `> \n> ${info.principal}\n`;
  }

  if (info.calorias) {
    md += `> \n> 📊 **${info.calorias}**\n`;
  }

  if (info.extras.length > 0) {
    md += `> \n> 📝 *${info.extras.join(' • ')}*\n`;
  }

  md += `\n`;

  // Status
  if (!CONFIG.mostrarInativos && produto.active === false) {
    md += `⚠️ **Produto temporariamente indisponível**\n\n`;
  }

  if (produto.id) {
    md += `*Referência: #${produto.id}*\n\n`;
  }

  return md;
}

function templateMinimalista(produto, index, categoriaSlug) {
  const info = extrairInfoDescricao(produto.description);

  let md = '';

  md += `**${limparTexto(produto.name)}**  \n`;
  md += `${formatarPreco(produto.price)}`;

  if (info.calorias) {
    md += ` • ${info.calorias}`;
  }

  if (!CONFIG.mostrarInativos && produto.active === false) {
    md += ` ⚠️`;
  }

  md += `\n\n`;

  return md;
}

// Seleciona template baseado na config
function gerarProduto(produto, index, categoriaSlug) {
  // Filtra produtos inativos se configurado
  if (!CONFIG.mostrarInativos && produto.active === false) {
    return CONFIG.template === 'compacto' || CONFIG.template === 'minimalista' 
      ? '' 
      : templatePadrao(produto, index, categoriaSlug);
  }

  switch (CONFIG.template) {
    case 'compacto':
      return templateCompacto(produto, index, categoriaSlug);
    case 'premium':
      return templatePremium(produto, index, categoriaSlug);
    case 'minimalista':
      return templateMinimalista(produto, index, categoriaSlug);
    default:
      return templatePadrao(produto, index, categoriaSlug);
  }
}

// ============================================
// AGRUPAMENTO POR CATEGORIA
// ============================================

function agruparPorCategoria(produtos) {
  const grupos = {};

  produtos.forEach(produto => {
    const categoria = produto.category || 'Outros';
    if (!grupos[categoria]) {
      grupos[categoria] = [];
    }
    grupos[categoria].push(produto);
  });

  return grupos;
}

// ============================================
// ESTATÍSTICAS
// ============================================

function calcularEstatisticas(produtos) {
  let comImagem = 0;
  let ativos = 0;
  let inativos = 0;
  const precos = [];
  const categorias = new Set();

  produtos.forEach(produto => {
    if (produto.image_url) comImagem++;
    if (produto.active === true) ativos++;
    if (produto.active === false) inativos++;
    if (produto.category) categorias.add(produto.category);

    const preco = parseFloat(produto.price);
    if (!isNaN(preco)) precos.push(preco);
  });

  let precoMedio = 0, precoMin = 0, precoMax = 0;
  if (precos.length > 0) {
    precoMedio = precos.reduce((a, b) => a + b, 0) / precos.length;
    precoMin = Math.min(...precos);
    precoMax = Math.max(...precos);
  }

  return {
    total: produtos.length,
    ativos,
    inativos,
    comImagem,
    semImagem: produtos.length - comImagem,
    percentualComImagem: produtos.length > 0 ? Math.round((comImagem / produtos.length) * 100) : 0,
    totalCategorias: categorias.size,
    categorias: Array.from(categorias).sort(),
    precoMedio,
    precoMin,
    precoMax,
    temPrecos: precos.length > 0
  };
}

// ============================================
// GERAÇÃO DO CATÁLOGO
// ============================================

function gerarCatalogo(produtos) {
  const blocos = [];
  const stats = calcularEstatisticas(produtos);

  // Cabeçalho
  blocos.push(`# ${CONFIG.tituloH1}`);

  if (CONFIG.nomeRestaurante) {
    blocos.push(`### ${CONFIG.nomeRestaurante}\n`);
  }

  blocos.push(`*Gerado em: ${new Date().toLocaleString('pt-BR', { 
    dateStyle: 'long', 
    timeStyle: 'short' 
  })}*\n`);

  // Estatísticas
  if (CONFIG.incluirEstatisticas) {
    blocos.push(`## 📊 Resumo do Cardápio\n`);
    blocos.push(`- **Total de produtos:** ${stats.total}`);
    blocos.push(`- **Produtos ativos:** ${stats.ativos}`);
    if (stats.inativos > 0) {
      blocos.push(`- **Produtos inativos:** ${stats.inativos}`);
    }
    blocos.push(`- **Categorias:** ${stats.totalCategorias}`);
    blocos.push(`- **Com imagem:** ${stats.comImagem} (${stats.percentualComImagem}%)`);

    if (stats.temPrecos) {
      blocos.push(`- **Faixa de preço:** ${formatarPreco(stats.precoMin)} a ${formatarPreco(stats.precoMax)}`);
      blocos.push(`- **Preço médio:** ${formatarPreco(stats.precoMedio)}`);
    }

    blocos.push('');
  }

  blocos.push(`---\n`);

  // Geração por categoria ou lista única
  if (CONFIG.agruparPorCategoria) {
    const grupos = agruparPorCategoria(produtos);
    const categoriasOrdenadas = Object.keys(grupos).sort();

    // Índice de categorias
    if (CONFIG.incluirIndice && CONFIG.template !== 'minimalista') {
      blocos.push(`## 📑 Índice por Categoria\n`);
      categoriasOrdenadas.forEach(categoria => {
        const slug = slugify(categoria);
        const emoji = getEmojiCategoria(categoria);
        const qtd = grupos[categoria].length;
        blocos.push(`- [${emoji} ${categoria}](#categoria-${slug}) (${qtd} ${qtd === 1 ? 'item' : 'itens'})`);
      });
      blocos.push(`\n---\n`);
    }

    // Gera produtos por categoria
    categoriasOrdenadas.forEach((categoria, catIndex) => {
      const slug = slugify(categoria);
      const emoji = getEmojiCategoria(categoria);
      const produtosCategoria = grupos[categoria];

      blocos.push(`## ${emoji} ${categoria} {#categoria-${slug}}\n`);

      const produtosMd = produtosCategoria
        .map((produto, i) => gerarProduto(produto, i, slug))
        .filter(md => md !== ''); // Remove vazios (inativos filtrados)

      blocos.push(produtosMd.join(''));

      if (catIndex < categoriasOrdenadas.length - 1) {
        blocos.push(`---\n`);
      }
    });

  } else {
    // Lista única sem agrupamento
    if (CONFIG.incluirIndice && CONFIG.template !== 'minimalista') {
      blocos.push(`## 📑 Índice de Produtos\n`);
      produtos.forEach((produto, i) => {
        const slug = slugify(produto.name || 'produto');
        blocos.push(`${i + 1}. [${limparTexto(produto.name)}](#produto-${produto.id || i}-${slug}) - ${formatarPreco(produto.price)}`);
      });
      blocos.push(`\n---\n`);
    }

    blocos.push(`## 🍽️ Todos os Produtos\n`);

    const produtosMd = produtos
      .map((produto, i) => gerarProduto(produto, i, 'geral'))
      .filter(md => md !== '');

    blocos.push(produtosMd.join(''));
  }

  // Footer
  blocos.push(`\n---\n`);
  blocos.push(`*${stats.total} ${stats.total === 1 ? 'produto' : 'produtos'} • `);
  blocos.push(`${stats.totalCategorias} ${stats.totalCategorias === 1 ? 'categoria' : 'categorias'} • `);
  blocos.push(`Template: ${CONFIG.template} • `);
  blocos.push(`Layout: ${CONFIG.layoutImagem}*`);

  return blocos.join('\n');
}

// ============================================
// EXECUÇÃO PRINCIPAL
// ============================================

try {
  const items = $input.all();

  if (!items || items.length === 0) {
    throw new Error('❌ Nenhum produto recebido no input');
  }

  const produtos = items.map(item => item.json);

  console.log(`✅ ${produtos.length} produtos recebidos`);

  // Validação
  const erros = validarTodosProdutos(produtos);
  if (erros.length > 0) {
    console.warn('⚠️ AVISOS DE VALIDAÇÃO:');
    erros.forEach(erro => console.warn(`  - ${erro}`));
  }

  // Debug primeiro produto
  if (produtos.length > 0) {
    console.log('\n🔍 PRIMEIRO PRODUTO:');
    console.log('  name:', produtos[0].name);
    console.log('  price:', produtos[0].price);
    console.log('  category:', produtos[0].category);
    console.log('  image_url:', produtos[0].image_url ? 'SIM' : 'NÃO');
    console.log('  active:', produtos[0].active);
  }

  // Gera catálogo
  const markdown = gerarCatalogo(produtos);
  const stats = calcularEstatisticas(produtos);

  console.log(`\n✅ Catálogo gerado com sucesso!`);
  console.log(`📊 Estatísticas:`);
  console.log(`  - ${stats.total} produtos (${stats.ativos} ativos, ${stats.inativos} inativos)`);
  console.log(`  - ${stats.totalCategorias} categorias`);
  console.log(`  - ${stats.comImagem} produtos com imagem (${stats.percentualComImagem}%)`);
  if (stats.temPrecos) {
    console.log(`  - Preço médio: ${formatarPreco(stats.precoMedio)}`);
  }
  console.log(`  - Template: ${CONFIG.template}`);
  console.log(`  - Layout: ${CONFIG.layoutImagem}`);

  return {
    json: {
      markdown: markdown,
      metadata: {
        total_produtos: stats.total,
        produtos_ativos: stats.ativos,
        produtos_inativos: stats.inativos,
        com_imagem: stats.comImagem,
        sem_imagem: stats.semImagem,
        percentual_com_imagem: stats.percentualComImagem,
        total_categorias: stats.totalCategorias,
        categorias: stats.categorias,
        preco_medio: stats.precoMedio,
        preco_minimo: stats.precoMin,
        preco_maximo: stats.precoMax,
        data_geracao: new Date().toISOString(),
        template_usado: CONFIG.template,
        layout_imagem: CONFIG.layoutImagem,
        agrupado_por_categoria: CONFIG.agruparPorCategoria
      }
    }
  };

} catch (error) {
  console.error('❌ ERRO:', error.message);
  console.error('Stack:', error.stack);

  return {
    json: {
      error: true,
      message: error.message,
      stack: error.stack,
      markdown: `# ⚠️ Erro ao Gerar Catálogo\n\n**Mensagem:** ${error.message}\n\n\`\`\`\n${error.stack}\n\`\`\``
    }
  };
}

/* 
===============================================
📚 GUIA DE USO - GERADOR DE CATÁLOGO RESTAURANTE
===============================================

🎨 TEMPLATES DISPONÍVEIS:
--------------------------
CONFIG.template = 'padrao'      → Completo com descrições e detalhes
CONFIG.template = 'compacto'    → Linha única por produto
CONFIG.template = 'premium'     → Layout luxo com blockquotes
CONFIG.template = 'minimalista' → Mínimo de informações

🖼️ LAYOUTS DE IMAGEM:
----------------------
CONFIG.layoutImagem = 'destaque'    → Imagem em bloco próprio
CONFIG.layoutImagem = 'lateral'     → Imagem ao lado (tabela)
CONFIG.layoutImagem = 'compacta'    → Imagem pequena inline
CONFIG.layoutImagem = 'sem-imagem'  → Não exibe imagens

⚙️ CONFIGURAÇÕES PRINCIPAIS:
----------------------------
- tituloH1: Título do catálogo
- nomeRestaurante: Nome do estabelecimento
- incluirImagens: true/false
- incluirIndice: true/false
- incluirEstatisticas: true/false
- agruparPorCategoria: true/false
- mostrarPrecoDestaque: true/false
- mostrarInativos: true/false

🎯 CAMPOS ESPERADOS NO JSON:
-----------------------------
OBRIGATÓRIOS:
- name: string (nome do produto)
- price: number/string (preço)

OPCIONAIS:
- description: string (descrição, calorias, etc)
- category: string (categoria do produto)
- image_url: string (URL da imagem)
- active: boolean (disponibilidade)
- id: number (identificador único)
- createdAt: string (data criação)
- updatedAt: string (data atualização)

📊 SAÍDA DO CÓDIGO:
-------------------
{
  markdown: "# Catálogo...",
  metadata: {
    total_produtos: 215,
    produtos_ativos: 200,
    com_imagem: 150,
    categorias: ["Entradas", "Pratos", ...],
    preco_medio: 45.50,
    ...
  }
}

✅ VALIDAÇÕES AUTOMÁTICAS:
--------------------------
- Verifica campos obrigatórios (name, price)
- Valida formato de preço
- Filtra produtos inativos (se configurado)
- Trata descrições com múltiplos formatos

🎨 EMOJIS POR CATEGORIA:
------------------------
Personalize no CONFIG.emojisPorCategoria:
{
  'Entradas': '🥗',
  'Pratos Principais': '🍖',
  'Pizzas': '🍕',
  'Sobremesas': '🍰',
  'Bebidas': '🥤'
}

💡 DICAS DE USO:
----------------
1. Comece com template 'padrao' para ver todas as opções
2. Use 'compacto' para cardápios muito grandes
3. Use 'premium' para menus de alta gastronomia
4. Combine layoutImagem='lateral' com template='padrao' para visual tipo "cardápio de restaurante"
5. Desative agruparPorCategoria para ordem cronológica

🔧 TROUBLESHOOTING:
-------------------
- Nenhum produto aparece? Verifique campo 'active'
- Imagens não aparecem? Verifique CONFIG.incluirImagens e image_url válidas
- Categorias erradas? Verifique campo 'category' nos produtos
- Preços estranhos? Certifique-se que 'price' é número válido

===============================================
*/
